import React from 'react';
import './Fleet.css';

const FLEET = [
  { 
    type: '4 Chỗ Sedan', 
    count: '200+ xe', 
    models: 'Toyota Vios, Hyundai Accent', 
    img: 'https://www.image2url.com/r2/default/images/1782302967863-b8fb6821-9056-43c9-911b-13c193316ab5.png', // Đã thay bằng link ảnh của bạn
    features: ['Điều hòa 2 chiều', 'Cáp sạc USB', 'Định vị GPS', 'Camera hành trình'] 
  },
  { type: '7 Chỗ MPV', count: '150+ xe', models: 'Toyota Innova, Mitsubishi Xpander', img: 'https://www.image2url.com/r2/default/images/1782303464530-3d7582c8-cc50-435c-8bbe-d5def80b8d4d.png', features: ['Ghế da cao cấp', 'Điều hòa tự động', 'Cốp rộng', 'Màn hình giải trí'] },
  { type: 'Limousine VIP', count: '50+ xe', models: 'Ford Tourneo, Hyundai Staria', img: 'https://www.image2url.com/r2/default/images/1782303575426-1048a77b-89d4-4d22-8bd1-0701510c567d.png', features: ['Ghế massage', 'WiFi riêng', 'Màn hình HD', 'Rèm che riêng tư'] },
];

export default function Fleet() {
  return (
    <section id="fleet" className="section">
      <div className="container">
        <div className="section-label">Đội xe</div>
        <h2 className="section-title">Đội xe hiện đại, sạch sẽ</h2>
        <p className="section-sub" style={{ marginBottom: 48 }}>
          400+ xe đời mới nhập khẩu 2020-2024, bảo dưỡng định kỳ mỗi 3 tháng.
        </p>
        <div className="grid-3">
          {FLEET.map((car, i) => (
            <div key={i} className="fleet-card card">

              {/* ĐOẠN ĐƯỢC SỬA LẠI ĐỂ HIỂN THỊ ĐƯỢC CẢ LINK ẢNH LẪN EMOJI */}
              <div className="fleet-card__img">
                {car.img.startsWith('http') ? (
                  <img 
                    src={car.img} 
                    alt={car.type} 
                    style={{ width: '100%', height: '100%', objectFit: 'cover' }} 
                  />
                ) : (
                  car.img
                )}
              </div>

              <div className="fleet-card__body">
                <div className="fleet-card__count">{car.count}</div>
                <h3 className="fleet-card__type">{car.type}</h3>
                <p className="fleet-card__models">{car.models}</p>
                <ul className="fleet-card__features">
                  {car.features.map((f, j) => (
                    <li key={j}><span>✓</span> {f}</li>
                  ))}
                </ul>
                <a href="#hero" className="btn btn-outline btn-sm fleet-card__cta">Đặt xe loại này</a>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
